snippets.C0644:
-- Caso: Búsqueda binaria (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0644
-- Entrada: TEMPORARY TABLE tmp_arr(pos INT PRIMARY KEY, val BIGINT) con pos 0..n-1
DELIMITER $$
CREATE PROCEDURE sp_solve_c0644(IN p_target BIGINT, OUT p_out INT)
BEGIN
  DECLARE v_lo INT DEFAULT 0;
  DECLARE v_hi INT;
  DECLARE v_mid INT;
  DECLARE v_val BIGINT;

  SELECT MAX(pos) INTO v_hi FROM tmp_arr;
  SET p_out = -1;

  loop1: WHILE v_lo <= v_hi DO
    SET v_mid = FLOOR((v_lo + v_hi) / 2);
    SELECT val INTO v_val FROM tmp_arr WHERE pos = v_mid;

    IF v_val = p_target THEN
      SET p_out = v_mid;
      LEAVE loop1;
    END IF;

    IF v_val < p_target THEN
      SET v_lo = v_mid + 1;
    ELSE
      SET v_hi = v_mid - 1;
    END IF;
  END WHILE;
END$$
DELIMITER ;

-- Demo
CREATE TEMPORARY TABLE tmp_arr(pos INT PRIMARY KEY, val BIGINT);
-- INSERT INTO tmp_arr VALUES (0,10),(1,20),(2,30);
SET @out = NULL;
CALL sp_solve_c0644(20, @out);
SELECT @out AS idx;

snippets.C0645:
-- Caso: Validar brackets (clásico) | Nivel: Intermedio | Categoría: Clásicos | ID: C0645
DELIMITER $$
CREATE PROCEDURE sp_solve_c0645(IN p_s TEXT, OUT p_out TINYINT)
BEGIN
  DECLARE v_stack TEXT DEFAULT '';
  DECLARE v_i INT DEFAULT 1;
  DECLARE v_n INT;
  DECLARE v_ch CHAR(1);
  DECLARE v_top CHAR(1);

  SET v_n = CHAR_LENGTH(p_s);
  SET p_out = 1;

  loop1: WHILE v_i <= v_n DO
    SET v_ch = SUBSTRING(p_s, v_i, 1);

    IF v_ch IN ('(', '[', '{') THEN
      SET v_stack = CONCAT(v_stack, v_ch);
    ELSEIF v_ch IN (')', ']', '}') THEN
      IF CHAR_LENGTH(v_stack) = 0 THEN
        SET p_out = 0;
        LEAVE loop1;
      END IF;

      SET v_top = SUBSTRING(v_stack, CHAR_LENGTH(v_stack), 1);
      SET v_stack = SUBSTRING(v_stack, 1, CHAR_LENGTH(v_stack) - 1);

      IF (v_top='(' AND v_ch<>')') OR (v_top='[' AND v_ch<>']') OR (v_top='{' AND v_ch<>'}') THEN
        SET p_out = 0;
        LEAVE loop1;
      END IF;
    END IF;

    SET v_i = v_i + 1;
  END WHILE;

  IF p_out=1 AND CHAR_LENGTH(v_stack)<>0 THEN
    SET p_out = 0;
  END IF;
END$$
DELIMITER ;

