snippets.C0646:
-- Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación | ID: C0646
DELIMITER $$
CREATE FUNCTION validate_rut(p_rut VARCHAR(32))
RETURNS TINYINT
DETERMINISTIC
BEGIN
  DECLARE clean VARCHAR(32);
  DECLARE body VARCHAR(32);
  DECLARE dv CHAR(1);
  DECLARE sumv INT DEFAULT 0;
  DECLARE mul INT DEFAULT 2;
  DECLARE i INT;
  DECLARE d INT;
  DECLARE modv INT;
  DECLARE dvCalc CHAR(1);

  SET clean = UPPER(REPLACE(REPLACE(REPLACE(p_rut, '.', ''), '-', ''), ' ', ''));
  IF CHAR_LENGTH(clean) < 2 THEN RETURN 0; END IF;

  SET body = LEFT(clean, CHAR_LENGTH(clean)-1);
  SET dv = RIGHT(clean, 1);

  IF body REGEXP '[^0-9]' THEN RETURN 0; END IF;

  SET i = CHAR_LENGTH(body);
  WHILE i > 0 DO
    SET d = CAST(SUBSTRING(body, i, 1) AS UNSIGNED);
    SET sumv = sumv + (d * mul);
    SET mul = IF(mul = 7, 2, mul + 1);
    SET i = i - 1;
  END WHILE;

  SET modv = 11 - (sumv MOD 11);
  SET dvCalc = IF(modv = 11, '0', IF(modv = 10, 'K', CAST(modv AS CHAR)));

  RETURN IF(dv = dvCalc, 1, 0);
END$$
DELIMITER ;

-- Demo
SELECT validate_rut('12.345.678-5') AS is_valid;

